import anthropic

client = anthropic.Anthropic()

# The model selects tools by reading their descriptions.
# It does not see the implementations — only name, description, and input_schema.

tools = [
    {
        "name": "read_file",
        "description": (
            "Read the full contents of a file. "
            "Use this to understand a file before modifying it. "
            "Returns the file content as a string."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "Absolute path to the file."},
            },
            "required": ["path"],
        },
    },
    {
        "name": "search_code",
        "description": (
            "Search the codebase for a string or regex pattern using ripgrep. "
            "Use this to locate function definitions, class names, or any text. "
            "Does NOT search the web. Returns matching lines with file:line numbers."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "pattern": {"type": "string", "description": "Regex pattern to search for."},
                "directory": {"type": "string", "description": "Directory to search. Defaults to repo root."},
            },
            "required": ["pattern"],
        },
    },
]

# Given the task "find where LoginError is defined", the model:
# 1. Reads the task: need to locate a symbol.
# 2. Scans descriptions: search_code matches "locate function definitions".
# 3. Reads input_schema: needs pattern (required), directory (optional).
# 4. Emits: tool_use {name: "search_code", input: {pattern: "class LoginError"}}

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    tools=tools,
    messages=[{"role": "user", "content": "Find where LoginError is defined."}],
)

# The model picks one tool per step. When two tools have overlapping descriptions,
# selection becomes unpredictable.

# BAD: two tools that both "read" something — model picks arbitrarily
BAD_TOOLS = [
    {"name": "read_file", "description": "Read a file."},
    {"name": "get_file_contents", "description": "Get the contents of a file."},
]

# GOOD: clearly different scope — model can distinguish them
GOOD_TOOLS = [
    {
        "name": "read_file",
        "description": (
            "Read the full contents of a single file. "
            "Returns the complete file as a string."
        ),
    },
    {
        "name": "read_file_range",
        "description": (
            "Read a specific line range of a file. "
            "Use when you only need part of a large file. "
            "Returns the selected lines only."
        ),
    },
]

# When consolidating is better than distinguishing:
# If two tools have genuinely overlapping scope, merge them into one with an
# optional parameter rather than maintaining two that confuse the model.
MERGED_TOOL = {
    "name": "read_file",
    "description": (
        "Read a file. Pass start_line and end_line to read only a portion."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "path": {"type": "string", "description": "Absolute path to read."},
            "start_line": {"type": "integer", "description": "First line to read (1-indexed). Omit to read from start."},
            "end_line": {"type": "integer", "description": "Last line to read (inclusive). Omit to read to end."},
        },
        "required": ["path"],
    },
}

import anthropic

client = anthropic.Anthropic()


def run_with_forced_read_first(path: str, task: str, tools: list[dict]) -> str:
    """
    Enforce read-before-write by forcing read_file on the first step,
    then switching to auto for the remainder of the run.
    """
    messages = [{"role": "user", "content": task}]

    # Step 1: forced read of the target file
    step1 = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=2048,
        tools=tools,
        tool_choice={"type": "tool", "name": "read_file"},
        messages=messages,
    )
    messages.append({"role": "assistant", "content": step1.content})

    # Execute the forced read and add the result
    for block in step1.content:
        if block.type == "tool_use" and block.name == "read_file":
            content = open(block.input["path"]).read()
            messages.append({
                "role": "user",
                "content": [{
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": content,
                }],
            })

    # Steps 2+: free selection
    for step in range(29):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools,
            tool_choice={"type": "auto"},
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": dispatch_tool(block.name, block.input),
                })
        messages.append({"role": "user", "content": tool_results})

    return "Max steps reached."
